%[text] DOADOPPLERDYNDUALSATURAECIPERF Performance comparison under dynamic geometry.
%[text] Compare four MLE baselines under a dual-satellite dynamic model:
%[text]   1\\) Single-satellite DoA MLE            (reference frame only)
%[text]   2\\) Dual-satellite DoA MLE              (reference frame only)
%[text]   3\\) Dual-satellite static DoA-Doppler   (reference frame only)
%[text]   4\\) Dual-satellite dynamic DoA-Doppler  (multi-frame joint)
%[text] 
%[text] In addition to the raw RMSE curves, this script records robust
%[text] diagnostics for the dynamic estimator:
%[text]   \- median error
%[text]   \- p95 error
%[text]   \- fail count / fail rate
%[text]   \- outlier count / outlier rate
%[text]   \- trimmed / winsorized RMSE
%[text] 
%[text] The robust curves are for diagnosis only. They should be interpreted
%[text] as "outlier-corrected evaluation" instead of replacing the raw RMSE.
clear(); close all;
%%
%[text] ## Parameters
numUsr = 1;
sampleRate = 512e6;
symbolRate = 128e6;
osf = sampleRate / symbolRate;
numSym = 512;
carrierFreq = 1e9;
wavelen = 299792458 / carrierFreq;
rng(253);

elemSpace = wavelen / 2;
numElem = [4 4];
pwrSource = 1;
E = referenceEllipsoid('sphere');

usrLla = [[37.78, 36.59, 0]', [37.58, 37.51, 0]'];
usrLla = usrLla(:, 1:numUsr);

utc0 = datetime([2026, 03, 12, 08, 53, 0], ...
  'TimeZone', 'UTC', ...
  'Format', 'yyyy-MM-dd HH:mm:ss.SSSSSS');
tle = tleread(localResolveTlePath("starlink_20260312.tle"));
arrUpa = createUpa(numElem, elemSpace);

numFrame = 10;
frameIntvlSec = 1 / 750;
refFrameIdx = round((numFrame + 1) / 2);
utcVec = utc0 + seconds(((1:numFrame) - refFrameIdx) * frameIntvlSec);

gridSize = [50 50];
searchMarginDeg = 5;
searchRange = [usrLla(1, 1) - searchMarginDeg, usrLla(1, 1) + searchMarginDeg; ...
               usrLla(2, 1) - searchMarginDeg, usrLla(2, 1) + searchMarginDeg];

optVerbose = false;

snrDb = -20:2:10;
numParam = numel(snrDb);
numRepeat = 1000;
%%
%[text] ## Robust evaluation options
robustOpt = struct();
robustOpt.numSigma = 4;
robustOpt.corrMode = 'winsor';   % 'winsor' or 'trim'
robustOpt.plotDiag = true;
robustOpt.reportStat = true;
%%
%[text] ## Multi-frame scene
[~, satAccessRef] = findVisibleSatFromTle(utc0, tle, usrLla);
[satIdx, satPickAux] = pickVisibleSatByElevation(satAccessRef, 2, 1, "available");
refSatIdxGlobal = satIdx(1);

sceneSeq = genMultiFrameScene(utcVec, tle, usrLla, satIdx, [], arrUpa, ...
  15, 55, "satellite", refSatIdxGlobal, refFrameIdx);
refFrameIdx = sceneSeq.refFrameIdx;
sceneRef = sceneSeq.sceneCell{refFrameIdx};

if sceneSeq.numSat ~= 2
  error('doaDopplerDynDualSatUraEciPerf:InvalidNumSat', ...
    'This script expects exactly two satellites.');
end

linkParamCell = cell(1, sceneSeq.numFrame);
for iFrame = 1:sceneSeq.numFrame
  linkParamCell{iFrame} = getLinkParam(sceneSeq.sceneCell{iFrame}, wavelen);
end

truth = buildDynTruthFromLinkParam(linkParamCell, sceneSeq.timeOffsetSec, sampleRate, 1);
truth.refSatIdxGlobal = refSatIdxGlobal;
truth.pickAux = satPickAux;
latlonTrue = usrLla(1:2, 1);
llaTrue = usrLla(:, 1);
fdRefTrueDyn = truth.fdRefFit;
fdRateTrueDyn = truth.fdRateFit;
fdRefTrueStat = truth.fdRefSeries(refFrameIdx);
%%
%[text] ## Pilot waveform
[pilotSym, pilotInfo] = genPilotSymbol(numUsr, numSym, 'pn', pwrSource); 

pulseOpt = struct();
pulseOpt.rolloff = 0.25;
pulseOpt.span = 8;

[pilotWave, waveInfo] = genPilotWaveform(pilotSym, symbolRate, osf, 'rrc', pulseOpt);
%%
%[text] ## Snapshot and estimator options
snapOpt = struct();
snapOpt.delayMode = 'phaseonly';
snapOpt.carrierPhaseMode = 'none';

simOpt = struct();
simOpt.steeringMode = 'framewise';
simOpt.accessMode = 'framewise';
simOpt.linkParamCell = linkParamCell;
simOpt.snapshotModelOpt = snapOpt;

doaGridCell = cell(1, sceneSeq.numSat);
for iSat = 1:sceneSeq.numSat
  doaGridCell{iSat} = genDoaGrid("latlon", 2, gridSize, searchRange, ...
    'eci', datevec(sceneSeq.utcRef), sceneRef.satPosEci(:, iSat), ...
    sceneRef.rotMat{iSat}, E);
end

fdRange = [0 1e3];
fdRateRange = [-500 50];

estOpt = struct();
estOpt.steeringMode = 'framewise';
estOpt.steeringRefFrameIdx = sceneSeq.refFrameIdx;
estOpt.phaseMode = 'continuous';
estOpt.fdRateMode = 'unknown';
estOpt.initFdCount = 81;
estOpt.useLogObjective = true;
estOpt.enableFdAliasUnwrap = true;
% The dynamic solver should refine around the MS-SF coarse DoA, but the
% local box must remain moderately wide. Over-tightening it was observed to
% break the coupled DoA-Doppler refinement and to create single-satellite
% biased solutions.
estOpt.initDoaHalfWidth = [0.005; 0.005];
%%
%[text] ## Outcome buffers
msePosDoaSingle = zeros(numParam, 1);
msePosDoaJoint = zeros(numParam, 1);
msePosDdStat = zeros(numParam, 1);
msePosDdDyn = zeros(numParam, 1);

mseFdDdStat = zeros(numParam, 1);
mseFdDdDyn = zeros(numParam, 1);

crbPosDdStat = zeros(numParam, 1);
crbPosDdDyn = zeros(numParam, 1);
crbFdDdStat = zeros(numParam, 1);
crbFdDdDyn = zeros(numParam, 1);

medPosDdDyn = nan(numParam, 1);
p95PosDdDyn = nan(numParam, 1);
trimRmsePosDdDyn = nan(numParam, 1);
winRmsePosDdDyn = nan(numParam, 1);
corrRmsePosDdDyn = nan(numParam, 1);
failCntPosDdDyn = zeros(numParam, 1);
outlierCntPosDdDyn = zeros(numParam, 1);
failRatePosDdDyn = zeros(numParam, 1);
outlierRatePosDdDyn = zeros(numParam, 1);

medFdDdDyn = nan(numParam, 1);
p95FdDdDyn = nan(numParam, 1);
trimRmseFdDdDyn = nan(numParam, 1);
winRmseFdDdDyn = nan(numParam, 1);
corrRmseFdDdDyn = nan(numParam, 1);
failCntFdDdDyn = zeros(numParam, 1);
outlierCntFdDdDyn = zeros(numParam, 1);
failRateFdDdDyn = zeros(numParam, 1);
outlierRateFdDdDyn = zeros(numParam, 1);
%%
%[text] ## Monte Carlo loop
progressbar('reset', numParam);

for iSnr = 1:numParam %[output:group:8f7ae55b]
  pwrNoise = pwrSource / (10^(snrDb(iSnr) / 10));

  sePosDoaSingle = nan(numRepeat, 1);
  sePosDoaJoint = nan(numRepeat, 1);
  sePosDdStat = nan(numRepeat, 1);
  sePosDdDyn = nan(numRepeat, 1);

  seFdDdStat = nan(numRepeat, 1);
  seFdDdDyn = nan(numRepeat, 1);

  isResolvedDdDyn = false(numRepeat, 1);
  exitflagDdDyn = nan(numRepeat, 1);
  fvalDdDyn = nan(numRepeat, 1);
  latlonValidDdDyn = false(numRepeat, 1);
  fdValidDdDyn = false(numRepeat, 1);

  parfor iRepeat = 1:numRepeat %[output:22a6eb36]
    pathGainCell = buildFramePathGain( ...
      sceneSeq.numFrame, sceneSeq.numSat, sceneSeq.numUser);

    [rxSigCell, ~, ~, ~, ~] = genMultiFrameSnapshots( ...
      sceneSeq, pilotWave, carrierFreq, waveInfo.sampleRate, ...
      pwrNoise, pathGainCell, simOpt);

    rxRef = rxSigCell{refFrameIdx};

    % ------------------------------------------------------------
    % 1) Single-satellite DoA-only MLE at the reference frame
    % ------------------------------------------------------------
    estDoaSingle = estimatorDoaMlePilotOpt( ...
      sceneRef.array{1}, wavelen, rxRef{1}, pilotWave, doaGridCell{1});

    latlonDoaSingle = localExtractLatlon(estDoaSingle);
    if ~isempty(latlonDoaSingle)
      sePosDoaSingle(iRepeat) = localCalcPosSe(latlonDoaSingle, llaTrue, E);
    end

    % ------------------------------------------------------------
    % 2) Dual-satellite DoA-only MLE at the reference frame
    % ------------------------------------------------------------
    estDoaJoint = estimatorDoaMlePilotOpt( ...
      sceneRef.array, wavelen, rxRef, pilotWave, doaGridCell);

    latlonDoaJoint = localExtractLatlon(estDoaJoint);
    if ~isempty(latlonDoaJoint)
      sePosDoaJoint(iRepeat) = localCalcPosSe(latlonDoaJoint, llaTrue, E);
    end

    % ------------------------------------------------------------
    % 3) Dual-satellite static DoA-Doppler MLE at the reference frame
    % ------------------------------------------------------------
    estDdStat = estimatorDoaDopplerMlePilotSfOpt( ...
      sceneRef, rxRef, pilotWave, carrierFreq, waveInfo.sampleRate, ...
      doaGridCell, fdRange);

    latlonDdStat = localExtractLatlon(estDdStat);
    if ~isempty(latlonDdStat)
      sePosDdStat(iRepeat) = localCalcPosSe(latlonDdStat, llaTrue, E);
    end

    fdRefDdStat = localExtractScalar(estDdStat, 'fdRefEst');
    if isfinite(fdRefDdStat)
      seFdDdStat(iRepeat) = (fdRefDdStat - fdRefTrueStat)^2;
    end

    % ------------------------------------------------------------
    % 4) Dual-satellite dynamic DoA-Doppler MLE using all frames
    % ------------------------------------------------------------
    dynOpt = estOpt;
    dynOpt.initDoaParam = estDoaJoint.doaParamEst(:);
    estDdDyn = estimatorDoaDopplerMlePilotMfOpt( ...
      sceneSeq, rxSigCell, pilotWave, carrierFreq, waveInfo.sampleRate, ...
      doaGridCell, fdRange, fdRateRange, [], optVerbose, dynOpt);

    latlonDdDyn = localExtractLatlon(estDdDyn);
    fdRefDdDyn = localExtractScalar(estDdDyn, 'fdRefEst');

    if ~isempty(latlonDdDyn)
      sePosDdDyn(iRepeat) = localCalcPosSe(latlonDdDyn, llaTrue, E);
      latlonValidDdDyn(iRepeat) = true;
    end

    if isfinite(fdRefDdDyn)
      seFdDdDyn(iRepeat) = (fdRefDdDyn - fdRefTrueDyn)^2;
      fdValidDdDyn(iRepeat) = true;
    end

    if isfield(estDdDyn, 'isResolved') && ~isempty(estDdDyn.isResolved)
      isResolvedDdDyn(iRepeat) = logical(estDdDyn.isResolved);
    end
    if isfield(estDdDyn, 'exitflag') && ~isempty(estDdDyn.exitflag)
      exitflagDdDyn(iRepeat) = estDdDyn.exitflag;
    end
    if isfield(estDdDyn, 'fval') && ~isempty(estDdDyn.fval)
      fvalDdDyn(iRepeat) = estDdDyn.fval;
    end
  end

  msePosDoaSingle(iSnr) = localMeanFinite(sePosDoaSingle);
  msePosDoaJoint(iSnr) = localMeanFinite(sePosDoaJoint);
  msePosDdStat(iSnr) = localMeanFinite(sePosDdStat);
  msePosDdDyn(iSnr) = localMeanFinite(sePosDdDyn);

  mseFdDdStat(iSnr) = localMeanFinite(seFdDdStat);
  mseFdDdDyn(iSnr) = localMeanFinite(seFdDdDyn);

  failMaskDdDyn = ~isResolvedDdDyn | ...
                  ~isfinite(exitflagDdDyn) | ...
                  ~isfinite(fvalDdDyn) | ...
                  ~latlonValidDdDyn | ...
                  ~fdValidDdDyn | ...
                  ~isfinite(sePosDdDyn) | ...
                  ~isfinite(seFdDdDyn);

  posStatDdDyn = localSummarizeMcSe(sePosDdDyn, failMaskDdDyn, robustOpt.numSigma);
  fdStatDdDyn = localSummarizeMcSe(seFdDdDyn, failMaskDdDyn, robustOpt.numSigma);

  medPosDdDyn(iSnr) = posStatDdDyn.median;
  p95PosDdDyn(iSnr) = posStatDdDyn.p95;
  trimRmsePosDdDyn(iSnr) = posStatDdDyn.trimRmse;
  winRmsePosDdDyn(iSnr) = posStatDdDyn.winRmse;
  corrRmsePosDdDyn(iSnr) = localPickCorrRmse(posStatDdDyn, robustOpt.corrMode);
  failCntPosDdDyn(iSnr) = posStatDdDyn.numFail;
  outlierCntPosDdDyn(iSnr) = posStatDdDyn.numOutlier;
  failRatePosDdDyn(iSnr) = posStatDdDyn.numFail / numRepeat;
  outlierRatePosDdDyn(iSnr) = posStatDdDyn.numOutlier / numRepeat;

  medFdDdDyn(iSnr) = fdStatDdDyn.median;
  p95FdDdDyn(iSnr) = fdStatDdDyn.p95;
  trimRmseFdDdDyn(iSnr) = fdStatDdDyn.trimRmse;
  winRmseFdDdDyn(iSnr) = fdStatDdDyn.winRmse;
  corrRmseFdDdDyn(iSnr) = localPickCorrRmse(fdStatDdDyn, robustOpt.corrMode);
  failCntFdDdDyn(iSnr) = fdStatDdDyn.numFail;
  outlierCntFdDdDyn(iSnr) = fdStatDdDyn.numOutlier;
  failRateFdDdDyn(iSnr) = fdStatDdDyn.numFail / numRepeat;
  outlierRateFdDdDyn(iSnr) = fdStatDdDyn.numOutlier / numRepeat;

  progressbar('advance'); %[output:6c5132c6]
end %[output:group:8f7ae55b]
%%
%[text] ## CRB evaluation
for iSnr = 1:numParam %[output:group:20dc2381]
  pwrNoise = pwrSource / (10^(snrDb(iSnr) / 10));

  crbStatOpt = struct();
  crbStatOpt.doaType = 'latlon';

  crbStat = crbPilotSfDoaDoppler( ...
    sceneRef, pilotWave, carrierFreq, waveInfo.sampleRate, ...
    latlonTrue, fdRefTrueStat, ones(sceneRef.numSat, 1), pwrNoise, crbStatOpt);

  crbDynOpt = struct();
  crbDynOpt.doaType = 'latlon';
  crbDynOpt.phaseMode = 'continuous';
  crbDynOpt.fdRateMode = 'unknown';
  crbDynOpt.steeringMode = estOpt.steeringMode;
  crbDynOpt.steeringRefFrameIdx = sceneSeq.refFrameIdx;

  crbDyn = crbPilotMfDoaDoppler( ... %[output:58f65b40] %[output:4a21395a] %[output:54ac6a68] %[output:696116a5] %[output:632e97c6] %[output:122391c4] %[output:5b5fd5c4] %[output:077b75d9] %[output:938d3cb3] %[output:47872c42] %[output:0b8edac0] %[output:5d30fc6a] %[output:0f777a75] %[output:08a13237] %[output:86a39d89] %[output:33dc1899]
    sceneSeq, pilotWave, carrierFreq, waveInfo.sampleRate, ... %[output:58f65b40] %[output:4a21395a] %[output:54ac6a68] %[output:696116a5] %[output:632e97c6] %[output:122391c4] %[output:5b5fd5c4] %[output:077b75d9] %[output:938d3cb3] %[output:47872c42] %[output:0b8edac0] %[output:5d30fc6a] %[output:0f777a75] %[output:08a13237] %[output:86a39d89] %[output:33dc1899]
    latlonTrue, fdRefTrueDyn, fdRateTrueDyn, ... %[output:58f65b40] %[output:4a21395a] %[output:54ac6a68] %[output:696116a5] %[output:632e97c6] %[output:122391c4] %[output:5b5fd5c4] %[output:077b75d9] %[output:938d3cb3] %[output:47872c42] %[output:0b8edac0] %[output:5d30fc6a] %[output:0f777a75] %[output:08a13237] %[output:86a39d89] %[output:33dc1899]
    ones(sceneSeq.numSat, sceneSeq.numFrame), pwrNoise, crbDynOpt); %[output:58f65b40] %[output:4a21395a] %[output:54ac6a68] %[output:696116a5] %[output:632e97c6] %[output:122391c4] %[output:5b5fd5c4] %[output:077b75d9] %[output:938d3cb3] %[output:47872c42] %[output:0b8edac0] %[output:5d30fc6a] %[output:0f777a75] %[output:08a13237] %[output:86a39d89] %[output:33dc1899]

  crbPosDdStat(iSnr) = localCalcPosCrb(crbStat(1:2, 1:2), llaTrue, E);
  crbPosDdDyn(iSnr) = localCalcPosCrb(crbDyn(1:2, 1:2), llaTrue, E);

  crbFdDdStat(iSnr) = real(crbStat(3, 3));
  crbFdDdDyn(iSnr) = real(crbDyn(3, 3));
end %[output:group:20dc2381]
%%
%[text] ## Plot performance curves
rmsePosDoaSingle = sqrt(msePosDoaSingle);
rmsePosDoaJoint = sqrt(msePosDoaJoint);
rmsePosDdStat = sqrt(msePosDdStat);
rmsePosDdDyn = sqrt(msePosDdDyn);

rmseFdDdStat = sqrt(mseFdDdStat);
rmseFdDdDyn = sqrt(mseFdDdDyn);

rmseCrbPosDdStat = sqrt(crbPosDdStat);
rmseCrbPosDdDyn = sqrt(crbPosDdDyn);
rmseCrbFdDdStat = sqrt(crbFdDdStat);
rmseCrbFdDdDyn = sqrt(crbFdDdDyn);

figure(); %[output:22308520]
tiledlayout(1, 2); %[output:22308520]

nexttile(); %[output:22308520]
semilogy(snrDb, rmsePosDoaSingle, '-o', ... %[output:22308520]
         snrDb, rmsePosDoaJoint, '-s', ... %[output:22308520]
         snrDb, rmsePosDdStat, '-d', ... %[output:22308520]
         snrDb, rmsePosDdDyn, '-^', ... %[output:22308520]
         snrDb, rmseCrbPosDdStat, '--d', ... %[output:22308520]
         snrDb, rmseCrbPosDdDyn, '--^'); %[output:22308520]
grid on; %[output:22308520]
xlabel('SNR (dB)'); %[output:22308520]
ylabel('Position RMSE (m)'); %[output:22308520]
legend({'Single-sat DoA', 'Dual-sat DoA', ... %[output:22308520]
        'Dual-sat Static DoA-Doppler', 'Dual-sat Dynamic DoA-Doppler', ... %[output:22308520]
        'CRB Static DoA-Doppler', 'CRB Dynamic DoA-Doppler'}, ... %[output:22308520]
        'Location', 'best'); %[output:22308520]
title(sprintf('Position RMSE (%d frames)', sceneSeq.numFrame)); %[output:22308520]

nexttile(); %[output:22308520]
semilogy(snrDb, rmseFdDdStat, '-d', ... %[output:22308520]
         snrDb, rmseFdDdDyn, '-^', ... %[output:22308520]
         snrDb, rmseCrbFdDdStat, '--d', ... %[output:22308520]
         snrDb, rmseCrbFdDdDyn, '--^'); %[output:22308520]
grid on; %[output:22308520]
xlabel('SNR (dB)'); %[output:22308520]
ylabel('fdRef RMSE (Hz)'); %[output:22308520]
legend({'Static DoA-Doppler', 'Dynamic DoA-Doppler', ... %[output:22308520]
        'CRB Static DoA-Doppler', 'CRB Dynamic DoA-Doppler'}, ... %[output:22308520]
        'Location', 'best'); %[output:22308520]
title(sprintf('Reference Doppler RMSE (%d frames)', sceneSeq.numFrame)); %[output:22308520]

if robustOpt.plotDiag %[output:group:34ba5915]
  corrLabel = localCorrLabel(robustOpt.corrMode);

  figure(); %[output:2e114429]
  tiledlayout(1, 2); %[output:2e114429]

  nexttile(); %[output:2e114429]
  semilogy(snrDb, rmsePosDdDyn, '-^', ... %[output:2e114429]
           snrDb, corrRmsePosDdDyn, '-v', ... %[output:2e114429]
           snrDb, medPosDdDyn, '-o', ... %[output:2e114429]
           snrDb, p95PosDdDyn, '-s', ... %[output:2e114429]
           snrDb, rmseCrbPosDdDyn, '--^'); %[output:2e114429]
  grid on; %[output:2e114429]
  xlabel('SNR (dB)'); %[output:2e114429]
  ylabel('Position Error (m)'); %[output:2e114429]
  legend({'Dynamic raw RMSE', corrLabel, 'Dynamic median', ... %[output:2e114429]
          'Dynamic p95', 'CRB Dynamic DoA-Doppler'}, ... %[output:2e114429]
          'Location', 'best'); %[output:2e114429]
  title('Dynamic Position Robust Diagnostics'); %[output:2e114429]

  nexttile(); %[output:2e114429]
  semilogy(snrDb, rmseFdDdDyn, '-^', ... %[output:2e114429]
           snrDb, corrRmseFdDdDyn, '-v', ... %[output:2e114429]
           snrDb, medFdDdDyn, '-o', ... %[output:2e114429]
           snrDb, p95FdDdDyn, '-s', ... %[output:2e114429]
           snrDb, rmseCrbFdDdDyn, '--^'); %[output:2e114429]
  grid on; %[output:2e114429]
  xlabel('SNR (dB)'); %[output:2e114429]
  ylabel('fdRef Error (Hz)'); %[output:2e114429]
  legend({'Dynamic raw RMSE', corrLabel, 'Dynamic median', ... %[output:2e114429]
          'Dynamic p95', 'CRB Dynamic DoA-Doppler'}, ... %[output:2e114429]
          'Location', 'best'); %[output:2e114429]
  title('Dynamic fdRef Robust Diagnostics'); %[output:2e114429]

  figure(); %[output:105be6ee]
  tiledlayout(1, 2); %[output:105be6ee]

  nexttile(); %[output:105be6ee]
  plot(snrDb, 100 * failRatePosDdDyn, '-o', ... %[output:105be6ee]
       snrDb, 100 * outlierRatePosDdDyn, '-s'); %[output:105be6ee]
  grid on; %[output:105be6ee]
  xlabel('SNR (dB)'); %[output:105be6ee]
  ylabel('Rate (%)'); %[output:105be6ee]
  legend({'Fail rate', 'Outlier rate'}, 'Location', 'best'); %[output:105be6ee]
  title('Dynamic Position Fail / Outlier Rate'); %[output:105be6ee]

  nexttile(); %[output:105be6ee]
  plot(snrDb, 100 * failRateFdDdDyn, '-o', ... %[output:105be6ee]
       snrDb, 100 * outlierRateFdDdDyn, '-s'); %[output:105be6ee]
  grid on; %[output:105be6ee]
  xlabel('SNR (dB)'); %[output:105be6ee]
  ylabel('Rate (%)'); %[output:105be6ee]
  legend({'Fail rate', 'Outlier rate'}, 'Location', 'best'); %[output:105be6ee]
  title('Dynamic fdRef Fail / Outlier Rate'); %[output:105be6ee]
end %[output:group:34ba5915]

if robustOpt.reportStat %[output:group:50e96fa5]
  localPrintRobustSummary(snrDb, rmsePosDdDyn, corrRmsePosDdDyn, ... %[output:9e4dbfb4]
    medPosDdDyn, p95PosDdDyn, failCntPosDdDyn, outlierCntPosDdDyn, ... %[output:9e4dbfb4]
    'Dynamic position'); %[output:9e4dbfb4]

  localPrintRobustSummary(snrDb, rmseFdDdDyn, corrRmseFdDdDyn, ... %[output:78612311]
    medFdDdDyn, p95FdDdDyn, failCntFdDdDyn, outlierCntFdDdDyn, ... %[output:78612311]
    'Dynamic fdRef'); %[output:78612311]
end %[output:group:50e96fa5]
%%
%[text] ## Optional snapshot save
saveExpSnapshot("doaDopplerDynDualSatUraEciPerf"); %[output:29d7d5f5]
%%
function latlonEst = localExtractLatlon(estResult)
%LOCALEXTRACTLATLON Extract the first [lat; lon] estimate.

latlonEst = [];

if ~isstruct(estResult) || ~isfield(estResult, 'latlonEst') || isempty(estResult.latlonEst)
  return;
end

latlonVec = estResult.latlonEst;
if size(latlonVec, 1) >= 2
  latlonEst = latlonVec(1:2, 1);
end

if isempty(latlonEst) || ~all(isfinite(latlonEst(:)))
  latlonEst = [];
end
end

function scalarVal = localExtractScalar(estResult, fieldName)
%LOCALEXTRACTSCALAR Extract the first scalar estimate from a result field.

scalarVal = nan;

if ~isstruct(estResult) || ~isfield(estResult, fieldName)
  return;
end

fieldVal = estResult.(fieldName);
if isempty(fieldVal)
  return;
end

scalarVal = fieldVal(1);
if ~isfinite(scalarVal)
  scalarVal = nan;
end
end

function meanVal = localMeanFinite(valVec)
%LOCALMEANFINITE Mean over finite entries.

finiteMask = isfinite(valVec(:));
if ~any(finiteMask)
  meanVal = nan;
  return;
end

meanVal = mean(valVec(finiteMask));
end

function posSe = localCalcPosSe(latlonEst, llaTrue, spheroid)
%LOCALCALCPOSSE Compute squared Euclidean position error in ECEF.

llaEst = [latlonEst(:); llaTrue(3)];
posEst = localLla2Ecef(llaEst, spheroid);
posTrue = localLla2Ecef(llaTrue, spheroid);
diffVec = posEst - posTrue;
posSe = real(sum(abs(diffVec).^2));
end

function posCrb = localCalcPosCrb(crbLatLon, llaTrue, spheroid)
%LOCALCALCPOSCRB Convert lat/lon CRB to ECEF position MSE lower bound.
%
%Input:
%  crbLatLon - 2x2 CRB of [lat; lon] in degree^2
%  llaTrue   - 3x1 true LLA [deg; deg; m]
%
%Output:
%  posCrb    - scalar ECEF position MSE lower bound in m^2

lat0 = llaTrue(1);
lon0 = llaTrue(2);
h0 = llaTrue(3);

epsDeg = 1e-6;

p0 = localLla2Ecef([lat0; lon0; h0], spheroid);
pLat = localLla2Ecef([lat0 + epsDeg; lon0; h0], spheroid);
pLon = localLla2Ecef([lat0; lon0 + epsDeg; h0], spheroid);

jacPos = [(pLat - p0) / epsDeg, ...
          (pLon - p0) / epsDeg];

posCov = jacPos * crbLatLon * jacPos.';
posCrb = real(trace(posCov));
end

function posEcef = localLla2Ecef(llaDeg, spheroid)
%LOCALLLA2ECEF Convert LLA [deg; deg; m] to ECEF [m].

[x, y, z] = geodetic2ecef(spheroid, llaDeg(1), llaDeg(2), llaDeg(3));
posEcef = [x; y; z];
end

function stat = localSummarizeMcSe(seVec, failMask, numSigma)
%LOCALSUMMARIZEMCSE Summarize Monte Carlo squared-error samples robustly.
%
%Input:
%  seVec     - squared error vector
%  failMask  - logical fail mask
%  numSigma  - outlier threshold factor on robust sigma
%
%Output:
%  stat      - structure with raw / robust summaries

if nargin < 3 || isempty(numSigma)
  numSigma = 4;
end

errVec = sqrt(real(seVec(:)));
failMask = logical(failMask(:));

invalidMask = ~isfinite(errVec);
failMask = failMask | invalidMask;

stat = struct();
stat.rawRmse = nan;
stat.trimRmse = nan;
stat.winRmse = nan;
stat.median = nan;
stat.p95 = nan;
stat.numFail = nnz(failMask);
stat.numOutlier = 0;
stat.outlierThr = nan;
stat.keepMask = false(size(errVec));
stat.outlierMask = false(size(errVec));

validMask = ~failMask;
if ~any(validMask)
  return;
end

validErr = errVec(validMask);

stat.rawRmse = sqrt(mean(validErr.^2));
stat.median = median(validErr);
stat.p95 = prctile(validErr, 95);

madErr = median(abs(validErr - stat.median));
sigmaRobust = 1.4826 * madErr;

sigmaFloor = 0.05 * max(stat.median, eps);
sigmaRobust = max(sigmaRobust, sigmaFloor);

stat.outlierThr = stat.median + numSigma * sigmaRobust;

outlierMask = false(size(errVec));
outlierMask(validMask) = errVec(validMask) > stat.outlierThr;

keepMask = validMask & ~outlierMask;

stat.outlierMask = outlierMask;
stat.keepMask = keepMask;
stat.numOutlier = nnz(outlierMask);

if any(keepMask)
  keepErr = errVec(keepMask);
  stat.trimRmse = sqrt(mean(keepErr.^2));
end

winErr = validErr;
winErr(winErr > stat.outlierThr) = stat.outlierThr;
stat.winRmse = sqrt(mean(winErr.^2));
end

function corrRmse = localPickCorrRmse(stat, corrMode)
%LOCALPICKCORRRMSE Select corrected RMSE by mode.

switch lower(string(corrMode))
  case "trim"
    corrRmse = stat.trimRmse;
  otherwise
    corrRmse = stat.winRmse;
end
end

function corrLabel = localCorrLabel(corrMode)
%LOCALCORRLABEL Build legend label for corrected RMSE.

switch lower(string(corrMode))
  case "trim"
    corrLabel = 'Dynamic trimmed RMSE';
  otherwise
    corrLabel = 'Dynamic winsorized RMSE';
end
end

function localPrintRobustSummary(snrDb, rawRmse, corrRmse, medErr, p95Err, ...
  failCnt, outlierCnt, tagStr)
%LOCALPRINTROBUSTSUMMARY Print one concise robust summary table.

fprintf('\n%s summary:\n', tagStr);
fprintf('  SNR(dB)   rawRMSE      corrRMSE     median       p95        failCnt   outlierCnt\n');
for iSnr = 1:numel(snrDb)
  fprintf('  %6.1f   %10.4g   %10.4g   %10.4g   %10.4g   %7d   %10d\n', ...
    snrDb(iSnr), rawRmse(iSnr), corrRmse(iSnr), medErr(iSnr), p95Err(iSnr), ...
    failCnt(iSnr), outlierCnt(iSnr));
end
end

function tlePath = localResolveTlePath(fileName)
%LOCALRESOLVETLEPATH Resolve one TLE file from common test locations.

candidateList = { ...
  fullfile('/tle', fileName), ...
  fullfile('tle', fileName), ...
  fullfile('test', 'data', 'tle', fileName), ...
  fullfile('..', 'data', 'tle', fileName)};

for iPath = 1:numel(candidateList)
  if exist(candidateList{iPath}, 'file')
    tlePath = candidateList{iPath};
    return;
  end
end

error('doaDopplerDynDualSatUraEciPerf:TleFileNotFound', ...
  'Unable to locate the TLE file "%s".', fileName);
end

